tool_calls:
set -euo pipefail
awk '
function trim(s){ sub(/^[[:space:]]+/,"",s); sub(/[[:space:]]+$/,"",s); return s }
function add_section(sec){
  if(!(sec in section_seen)){
    section_seen[sec]=1
    section_order[++section_count]=sec
  }
}
function add_key(sec,key){
  idx=sec SUBSEP key
  if(!(idx in key_seen)){
    key_seen[idx]=1
    key_order[sec, ++key_count[sec]] = key
  }
}
FNR==NR{
  line=$0
  sub(/\r$/, "", line)
  if(line ~ /^[[:space:]]*$/ || line ~ /^[[:space:]]*[#;]/) next
  if(match(line, /^[[:space:]]*\[([^]]+)\][[:space:]]*$/, m)){
    sec=m[1]
    add_section(sec)
    default_section[sec]=1
    next
  }
  if(sec=="" || index(line,"=")==0) next
  key=trim(substr(line,1,index(line,"=")-1))
  val=trim(substr(line,index(line,"=")+1))
  add_section(sec)
  add_key(sec,key)
  vals[sec SUBSEP key]=val
  default_key[sec SUBSEP key]=1
  next
}
{
  line=$0
  sub(/\r$/, "", line)
  if(line ~ /^[[:space:]]*$/ || line ~ /^[[:space:]]*[#;]/) next
  if(match(line, /^[[:space:]]*\[([^]]+)\][[:space:]]*$/, m)){
    sec=m[1]
    add_section(sec)
    next
  }
  if(sec=="" || index(line,"=")==0) next
  key=trim(substr(line,1,index(line,"=")-1))
  val=trim(substr(line,index(line,"=")+1))
  add_section(sec)
  add_key(sec,key)
  vals[sec SUBSEP key]=val
}
END{
  for(s=1; s<=section_count; s++){
    sec=section_order[s]
    print "[" sec "]"
    for(i=1; i<=key_count[sec]; i++){
      key=key_order[sec,i]
      idx=sec SUBSEP key
      if(idx in vals) print key "=" vals[idx]
    }
    if(s<section_count) print ""
  }
}
' /config/defaults.ini /config/custom.ini > /config/merged.ini

cat /config/merged.ini

